mapper.select:
select visitor_id, created_at
from visit_events
where event_type = 'pageview' and created_at >= #{start} and created_at < #{end}

select id, visitor_id, ip, url, user_agent, referrer, event_type, event_name, created_at
from visit_events


    and (lower(url) like #{keyword} or lower(title) like #{keyword} or lower(referrer) like #{keyword})


    and visitor_id = #{visitorId}


    and ip = #{ip}



      and ip <> #{excluded}



    and created_at >= #{startInclusive}


    and created_at < #{endExclusive}


order by created_at desc, id desc
